using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with a default resolver so metadata is auto-generated
var options = new JsonSerializerOptions
{
    TypeInfoResolver = JsonSerializer.IsReflectionEnabledByDefault
        ? new DefaultJsonTypeInfoResolver()
        : JsonSerializerContext.Default // won't happen here, but keeps it explicit
};

// ── 1. Strongly-typed metadata via the generic GetTypeInfo<T>() ──
JsonTypeInfo<Person> personMeta = (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));
Console.WriteLine($"Type  : {personMeta.Type.Name}");
Console.WriteLine($"Props : {string.Join(", ", personMeta.Properties.Select(p => p.Name))}");
Console.WriteLine();

// ── 2. Probe without throwing via TryGetTypeInfo ──
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
    Console.WriteLine($"Person metadata found  – kind: {found!.Kind}");
else
    Console.WriteLine("Person metadata NOT available");

// Ask about a type the resolver *can* handle but hasn't seen yet
if (options.TryGetTypeInfo(typeof(int), out _))
    Console.WriteLine("int    metadata found");

// Ask about a type that has no resolver at all (empty composite)
var empty = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine()   // resolves nothing
};

if (empty.TryGetTypeInfo(typeof(Person), out _))
    Console.WriteLine("Person metadata found in empty resolver");
else
    Console.WriteLine("Person metadata NOT available in empty resolver (no exception!)");

// ── Helper type ──
record Person(string Name, int Age);

